{"version":3,"file":"creative.js","sources":["pages/creative/creative.vue","../uniPage:/cGFnZXMvY3JlYXRpdmUvY3JlYXRpdmUudnVl"],"sourcesContent":["<script setup lang=\"ts\">\nimport {ref, onMounted, onUnmounted, computed} from 'vue'\nimport BaseLayout from \"@/layouts/BaseLayout.vue\";\n\nimport TnWaterFall from '@tuniao/tnui-vue3-uniapp/components/water-fall/src/water-fall.vue'\nimport {request} from \"@/utils/request.ts\";\nimport type {IDrawHistoryItem} from \"@/types\";\nimport TnGraphicCard from 'tnuiv3p-tn-graphic-card/index.vue'\nimport MyGraphicCard from \"@/components/custom/MyGraphicCard/MyGraphicCard.vue\";\nimport {formatDateTime} from \"@/utils/common.ts\";\n\nonMounted(()=>{\n  getTestImageData()\n})\n\nonUnmounted(()=>{\n  //   销毁当前组件\n  imageData.value=[]\n})\n\n\nconst getTestImageData = async () => {\n  imageData.value = await request<IDrawHistoryItem[]>('draw/history/findMany', {\n    method: 'POST',\n    data: {\n      history: {\n        is_deleted: false,\n        is_public: true,\n      }\n    }\n  })\n}\nconst  imageData=ref<IDrawHistoryItem[]>([])\n\n/**图文卡片展示的数据 */\nconst graphicDatas = computed(()=>{\n  return imageData.value.map(item =>{\n    return {\n      id: item._id,\n      avatar:item.user_id?.avatar_url||'',\n      username:item.user_id?.nickname||item.user_id?.username,\n      title:item.options?.workflow_title,\n      description:formatDateTime(new Date(item.created_at)),\n      tags:item.tags,\n      content:item.params?.positive?.slice(0,120)+\"...\",\n      images:(()=>{\n        // 生成参数\n        const inputImages=[]\n        for(const key  in item.params){\n          if (key.startsWith('image_path_') && item.params[key]){\n            inputImages.push(item.params[key])\n          }\n        }\n        if(!item.output){\n          return inputImages\n        }\n        return [...inputImages,...item.output]\n      })(),\n      commentCount:item.comment?.length\n    }\n  })\n})\n\n\n// const graphicData = {\n//   id: 1,\n//   avatar: 'https://tnuiimage.tnkjapp.com/uniapp_market/circle/3-image.jpg',\n//   title: '文章标题',\n//   description: '2023年6月30日',\n//   tags: ['标签1', '标签2'],\n//   content:\n//       '看看打开打开年份记得当年开始放假哦额外欺骗人u饿哦漂亮放佛怕打雷舒服呢我脾气破费了发多少呢；否，可能打飞机哦喷泉哦怕可能地方打开螺丝粉年份的肌肤看能否。',\n//   images: [\n//     'https://tnuiimage.tnkjapp.com/swiper/ad1.jpg',\n//     'https://tnuiimage.tnkjapp.com/swiper/ad2.jpg',\n//     'https://tnuiimage.tnkjapp.com/swiper/ad3.jpg',\n//     'https://tnuiimage.tnkjapp.com/swiper/ad4.jpg',\n//   ],\n//   viewCount: 100,\n//   commentCount: 101,\n//   likeCount: 102,\n//   viewUserAvatars: [\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/1.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/2.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/3.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/4.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/5.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/6.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/7.png',\n//     'https://tnuiimage.tnkjapp.com/avatar/normal/8.png',\n//   ],\n// }\n\n</script>\n\n<template>\n\t<fui-background-image src=\"@/src/static/Home2 (1).jpgHome2(1).jpg\">  </fui-background-image>\n\t\n  <BaseLayout>\n    <view>\n      <up-status-bar/>\n      <template v-for=\"graphicData in graphicDatas\">\n        <MyGraphicCard\n            :avatar=\"graphicData.avatar\"\n            :title=\"graphicData.title\"\n            :username=\"graphicData.username\"\n            :description=\"graphicData.description\"\n            :tags=\"graphicData.tags\"\n            :content=\"graphicData.content\"\n            :images=\"graphicData.images\"\n            :view-count=\"graphicData.viewCount\"\n            :comment-count=\"graphicData.commentCount\"\n            :like-count=\"graphicData.likeCount\"\n            :view-user-avatars=\"graphicData.viewUserAvatars\"\n        ></MyGraphicCard>\n      </template>\n    </view>\n\n\n   <!-- <TnWaterFall :data=\"imageData\" mode=\"calc\"> -->\n     <!-- <template #left=\"{ item }\">\n       <view class=\"image-data\">\n         <image class=\"image\" :src=\"item.output[0]\" mode=\"widthFix\" />\n       </view>\n     </template> -->\n     <!-- <template #right=\"{ item }\">\n       <view class=\"image-data\">\n         <image class=\"image\" :src=\"item.output[0]\" mode=\"widthFix\" />\n       </view>\n     </template> -->\n   <!-- </TnWaterFall> -->\n  </BaseLayout>\n  <view style=\"height: 200rpx;\">  <fui-footer text=\"Copyright © 2021 Fuzi-AI\"></fui-footer></view>\n</template>\n\n<style scoped lang=\"scss\">\n.image-data {\n  width: calc(100% - 20rpx);\n  margin: 10rpx;\n\n  .image {\n    width: 100%;\n    height: auto;\n  }\n}\n\n</style>","import MiniProgramPage from 'C:/Users/35577/Downloads/easyai-uniapp-aigc/src/pages/creative/creative.vue'\nwx.createPage(MiniProgramPage)"],"names":["onMounted","onUnmounted","request","ref","computed","formatDateTime"],"mappings":";;;;;;;;;;;;;;;;AAEA,MAAA,aAAuB,MAAA;AAMvB,MAAA,gBAA0B,MAAA;;;;AAG1BA,kBAAAA,UAAU,MAAI;AACK,uBAAA;AAAA,IAAA,CAClB;AAEDC,kBAAAA,YAAY,MAAI;AAEd,gBAAU,QAAM,CAAC;AAAA,IAAA,CAClB;AAGD,UAAM,mBAAmB,YAAY;AACzB,gBAAA,QAAQ,MAAMC,cAAA,QAA4B,yBAAyB;AAAA,QAC3E,QAAQ;AAAA,QACR,MAAM;AAAA,UACJ,SAAS;AAAA,YACP,YAAY;AAAA,YACZ,WAAW;AAAA,UAAA;AAAA,QACb;AAAA,MACF,CACD;AAAA,IACH;AACO,UAAA,YAAUC,cAAwB,IAAA,EAAE;AAGrC,UAAA,eAAeC,cAAAA,SAAS,MAAI;AACzB,aAAA,UAAU,MAAM,IAAI,CAAO,SAAA;;AACzB,eAAA;AAAA,UACL,IAAI,KAAK;AAAA,UACT,UAAO,UAAK,YAAL,mBAAc,eAAY;AAAA,UACjC,YAAS,UAAK,YAAL,mBAAc,eAAU,UAAK,YAAL,mBAAc;AAAA,UAC/C,QAAM,UAAK,YAAL,mBAAc;AAAA,UACpB,aAAYC,aAAAA,eAAe,IAAI,KAAK,KAAK,UAAU,CAAC;AAAA,UACpD,MAAK,KAAK;AAAA,UACV,WAAQ,gBAAK,WAAL,mBAAa,aAAb,mBAAuB,MAAM,GAAE,QAAK;AAAA,UAC5C,SAAQ,MAAI;AAEV,kBAAM,cAAY,CAAC;AACT,uBAAA,OAAQ,KAAK,QAAO;AAC5B,kBAAI,IAAI,WAAW,aAAa,KAAK,KAAK,OAAO,GAAG,GAAE;AACpD,4BAAY,KAAK,KAAK,OAAO,GAAG,CAAC;AAAA,cAAA;AAAA,YACnC;AAEC,gBAAA,CAAC,KAAK,QAAO;AACP,qBAAA;AAAA,YAAA;AAET,mBAAO,CAAC,GAAG,aAAY,GAAG,KAAK,MAAM;AAAA,UAAA,GACpC;AAAA,UACH,eAAa,UAAK,YAAL,mBAAc;AAAA,QAC7B;AAAA,MAAA,CACD;AAAA,IAAA,CACF;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;AC5DD,GAAG,WAAW,eAAe;"}
